import{_ as t,o as r,c as p,ag as s}from"./chunks/framework.ETe_P6d1.js";const e="/kaiping-reports/assets/1.DCRmKglh.jpg",o="/kaiping-reports/assets/2.ht2YIQXz.png",n="/kaiping-reports/assets/3.D0CGzAsN.jpg",i="/kaiping-reports/assets/4.PbKYsLl8.jpg",_="/kaiping-reports/assets/5.Cdhgh7p6.jpg",g="/kaiping-reports/assets/6.Cj5t5B9k.jpg",l="/kaiping-reports/assets/7.uEsi_yHE.jpg",h="/kaiping-reports/assets/8.qU1DVrb9.jpg",m="/kaiping-reports/assets/9.DJGLjUVW.jpg",c="/kaiping-reports/assets/10.CN6eGVQE.jpg",d="/kaiping-reports/assets/11.CsLSPhM3.jpg",u="/kaiping-reports/assets/12.BJ4wWWRu.jpg",J=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reports/许嘉怡/许嘉怡_关于关于开平近代建筑遗产保护与活态传承的调研报告.md","filePath":"reports/许嘉怡/许嘉怡_关于关于开平近代建筑遗产保护与活态传承的调研报告.md"}'),b={name:"reports/许嘉怡/许嘉怡_关于关于开平近代建筑遗产保护与活态传承的调研报告.md"};function k(q,a,f,P,x,j){return r(),p("div",null,[...a[0]||(a[0]=[s('<h4 id="关于开平近代建筑遗产保护与活态传承调研报告" tabindex="-1"><strong>关于<strong><strong>开平近代建筑遗产保护与活态传承</strong></strong>调研报告</strong> <a class="header-anchor" href="#关于开平近代建筑遗产保护与活态传承调研报告" aria-label="Permalink to &quot;**关于****开平近代建筑遗产保护与活态传承****调研报告**&quot;">​</a></h4><p><em><strong>*专业调研报告内容：*</strong></em></p><h4 id="一、-引言" tabindex="-1">**一、**<strong>引言</strong> <a class="header-anchor" href="#一、-引言" aria-label="Permalink to &quot;**一、****引言**&quot;">​</a></h4><p>开平近代建筑是侨乡文化、中西建筑技术与地方生活方式结合的重要遗产类型。这些建筑包括碉楼、骑楼、华侨民居、墟市公共建筑等，不仅反映了近代华侨的生活理想，也体现了本土营造技艺与西方建筑语言的融合。随着社会发展，许多曾经使用频繁的旧墟建筑、粮仓、民居逐渐闲置，面临老化、失修、功能不适应等问题。</p><p>2007 年，开平碉楼与村落被列入世界文化遗产，侨乡建筑的保护与活化越来越受到重视。本次考察以开平多个典型地点为对象，重点关注近代建筑的****遗产保护与活态传承、场所重构****问题，通过对立园、仓东村、塘口墟、赤坎古镇的比较分析，探讨历史建筑如何在当代重新焕发活力，如何在保护真实性的前提下适应新的功能需求，为历史建筑的可持续发展提供思考。</p><h4 id="二、-理论基础-活态传承与场所重构" tabindex="-1">**二、**<strong>理论基础：活态传承与场所重构</strong> <a class="header-anchor" href="#二、-理论基础-活态传承与场所重构" aria-label="Permalink to &quot;**二、****理论基础：活态传承与场所重构**&quot;">​</a></h4><p>在文化遗产保护领域，****活态传承****强调遗产不是静止的标本，而应在持续使用中保持生命力，使其价值得以延续。与传统单纯以修复建筑、开发旅游为目的的方式不同，现代遗产保护更加注重社区生活、文化脉络、历史环境的整体保护。</p><p>相关研究指出，乡村遗产的保护不应只停留在建筑外观修复，更应关注生活方式、社区结构、文化记忆的延续。真正的保护，是让建筑继续被合理使用，让社区保持活力，让历史空间在当代依然具有存在的意义。这种理念也被称为 “保育与发展”，即在保护遗产价值的基础上，实现可持续的发展，而不是单纯追求经济效益。</p><h4 id="三、案例分析" tabindex="-1">三、<strong>案例分析</strong> <a class="header-anchor" href="#三、案例分析" aria-label="Permalink to &quot;三、**案例分析**&quot;">​</a></h4><h3 id="_3-1-塘口墟-设计下乡引领的旧墟整体活化" tabindex="-1"><em><strong>*3.1 塘口墟：*</strong></em><em><strong>*设计下乡引领的旧墟整体活化*</strong></em> <a class="header-anchor" href="#_3-1-塘口墟-设计下乡引领的旧墟整体活化" aria-label="Permalink to &quot;***\\*3.1 塘口墟：\\*******\\*设计下乡引领的旧墟整体活化\\****&quot;">​</a></h3><p>塘口墟是开平侨乡近代墟市建筑的集中区域，近年来在 “设计下乡” 政策推动下，成为旧建筑活化利用的典型地区。通过政府、村集体、设计团队、运营机构多方协作，大量闲置旧粮仓、旧粮站、骑楼建筑得到重新利用，形成了一批具有代表性的改造项目。</p><p><img src="'+e+'" alt="图1 塘口墟街道风貌"></p><p><img src="'+o+'" alt="图2 先锋天下粮仓书店"></p><p>先锋天下粮仓书店由 20 世纪 70 年代的公社粮仓改造而成。项目最大的特点是****完整保留原有建筑形态与结构****，不破坏墙体、屋顶、空间尺度，只在内部进行功能置换，将过去储存粮食的封闭大空间，转变为阅读、展览、文创、休闲于一体的文化场所。这种改造方式以最小的干预实现了空间再生，使工业遗产重新成为公共文化地标。</p><p><img src="'+n+'" alt="图3 粮仓内部空间"></p><p>无名营造社与半分咖啡由旧粮站改造而来，是塘口墟另一处重要的微更新实践。</p><p><img src="'+i+'" alt="图4 无名营造社--半分咖啡入口"></p><p><img src="'+_+'" alt="图5 无名营造庭院"></p><p><img src="'+g+'" alt="图6 半分咖啡内部屋顶细节"></p><p>建筑原本破损严重，改造中保留了骑楼界面、红砖肌理、木梁结构，只对损坏部分进行修复。空间被重新组织为咖啡区、交流区、展厅和工作室，形成小型乡创基地，依靠长期运营保持活力，是小规模历史建筑活化的优秀案例。</p><h3 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h3><h3 id="_3-2-仓东村-社区参与式的遗产保育实践" tabindex="-1"><em><strong>*3.2*</strong></em> <em><strong>*仓东村：社区参与式的遗产保育实践*</strong></em> <a class="header-anchor" href="#_3-2-仓东村-社区参与式的遗产保育实践" aria-label="Permalink to &quot;***\\*3.2\\**** ***\\*仓东村：社区参与式的遗产保育实践\\****&quot;">​</a></h3><p>仓东村是开平侨乡历史悠久的村落，保留了大量中西合璧的民居、祠堂与碉楼，是研究侨乡文化景观的重要样本。与旅游开发模式不同，仓东村采用以社区为主体的****活态保育方式****，强调村民参与、生活延续、文化传承。</p><p><img src="'+l+'" alt="图7 仓东村祠堂外部"></p><p><img src="'+h+'" alt="图8 仓东村祠堂内部"></p><p>仓东村的保护工作从修复祠堂开始，坚持使用传统材料与工艺，尽可能保留建筑的历史痕迹。村落保护不搞大拆大建，不将村民迁出，而是让村民继续生活其中，祠堂、晒谷场等公共空间仍用于传统仪式与日常活动。这种模式不仅保护了建筑，更保护了村落的社会组织、信仰文化与生活节奏，让遗产在真实生活场景中得以延续。</p><p><em><strong>*3.3 立园：博物馆化保护与静态展示*</strong></em></p><p>立园是华侨园林的杰出代表，建筑装饰华丽，空间布局精巧，中西合璧特征极为明显。目前立园采用****博物馆化保护模式****，以文物修缮和原状展示为主，建筑、装饰、园林都得到细致修复，向观众呈现近代华侨园林的历史面貌。</p><p><img src="'+m+'" alt="图9 立园泮立楼外立面"></p><p><img src="'+c+'" alt="图10 立园园林空间"></p><p>这种模式的优点是能够最大限度保护建筑的真实性与艺术价值，但博物馆化展示也使建筑失去了日常生活功能，空间体验以参观为主，与当代生活的联系相对较弱。</p><p><em><strong>*3.4 赤坎古镇：整体更新与文旅场所重构*</strong></em></p><p>赤坎古镇以规模庞大的骑楼街著称，是近代侨乡商业文化的集中体现。近年来赤坎进行了整体修缮与环境提升，保留骑楼肌理与街巷格局，对建筑立面、结构、街道空间进行系统性修复，并植入民宿、餐饮、文创、体验等旅游业态。</p><p><img src="'+d+'" alt="图11 赤坎古街骑楼街景"></p><p><img src="'+u+'" alt="图12 赤坎古镇骑楼街景"></p><p>整体更新使赤坎的历史风貌得以重现，但原本的生活社区逐渐转变为旅游景区，原住民生活场景减少，历史空间的真实性与日常生活性有所弱化。</p><h4 id="四、批判性思考" tabindex="-1"><strong>四、批判性思考</strong> <a class="header-anchor" href="#四、批判性思考" aria-label="Permalink to &quot;**四、批判性思考**&quot;">​</a></h4><p>通过对比四个地点的保护与活化方式，可以看出开平近代建筑的保护呈现出明显的多元化特征。</p><p>立园的博物馆化保护适合高等级文物建筑，能完整保留历史信息，但缺乏活态使用；</p><p>仓东村的社区保育模式最贴近活态传承理念，但资金与推广能力有限；</p><p>塘口墟的设计下乡与微更新可复制性强，但依赖专业团队与运营能力；</p><p>赤坎的整体开发提升快，但容易出现商业化偏重、社区性减弱的问题。</p><p>总体来看，当前历史建筑保护仍存在一些普遍问题：部分项目重视视觉效果而忽视使用功能；普通历史建筑保护力度不足；社区参与程度有待提高；活化模式容易同质化。真正的活态传承，应该兼顾历史真实性、功能适用性、社区共生性。</p><h4 id="五、结论" tabindex="-1"><strong>五、结论</strong> <a class="header-anchor" href="#五、结论" aria-label="Permalink to &quot;**五、结论**&quot;">​</a></h4><p>开平近代建筑是侨乡历史、文化、技术与生活的综合载体，其保护与活化不应只有一种模式。通过本次考察可以看出，遗产保护的关键在于****尊重历史、适应现代、回归生活****。</p><p>塘口墟的旧建筑活化证明，通过微更新、功能植入、长期运营，可以让废弃空间重新成为社区活力节点。仓东村的实践则表明，以村民为主体、以生活为核心、以文化传承为目标的保育模式，是乡村遗产可持续发展的重要方向。</p><p>未来历史建筑的保护与场所重构，应坚持分类指导、最小干预、功能适配、多方参与，让历史建筑真正 “活起来”，使其既保留历史记忆，又能融入当代生活，成为连接过去与现在的活态空间。</p><h4 id="附录-调研记录" tabindex="-1"><strong>附录：调研记录</strong> <a class="header-anchor" href="#附录-调研记录" aria-label="Permalink to &quot;**附录：调研记录**&quot;">​</a></h4><h3 id="_6-1-图片清单" tabindex="-1"><em><strong>*6.1 图片清单*</strong></em> <a class="header-anchor" href="#_6-1-图片清单" aria-label="Permalink to &quot;***\\*6.1 图片清单\\****&quot;">​</a></h3><p>图 5 塘口墟街道风貌</p><p>图 2 先锋天下粮仓书店</p><p>图 3 粮仓内部空间</p><p>图 4 无名营造社--半分咖啡入口</p><p>图 5 无名营造庭院</p><p>图 6 半分咖啡内部屋顶细节</p><p>图7 仓东村祠堂外部</p><p>图 8 仓东村祠堂内部</p><p>图 9 立园泮立楼外立面</p><p>图 10 立园园林空间</p><p>图 11 赤坎古街骑楼街景</p><p>图 12 赤坎古镇骑楼街景</p><h3 id="-1" tabindex="-1"><a class="header-anchor" href="#-1" aria-label="Permalink to &quot;&quot;">​</a></h3><h3 id="_6-2-参考文献" tabindex="-1"><em><strong>*6.2 参考文献*</strong></em> <a class="header-anchor" href="#_6-2-参考文献" aria-label="Permalink to &quot;***\\*6.2 参考文献\\****&quot;">​</a></h3><p>[1] 谭金花。广东开平侨乡民国建筑装饰的特点与成因及其社会意义 (1911－1949)[J]. 华南理工大学学报 (社会科学版),2013,15 (03):54-60.</p><p>[2] 谭金花。乡村文化遗产保育与发展的研究及实践探索 —— 以广东开平仓东村为例 [J]. 南方建筑，2015 (01):18-22.</p><p>[3] 林巧欣。文化景观视角下开平碉楼与村落的保护和发展研究 —— 以仓东村为例 [J]. 房地产世界，2023 (19):18-21.</p><p>[4] 广东省住房和城乡建设厅。广东省开平市塘口镇：设计下乡引领乡村建设高质量发展 [J]. 城乡建设，2022 (14):51-53.</p><p>[5] 广东省文物考古研究所。开平碉楼 [M]. 北京：文物出版社，2007.</p>',68)])])}const D=t(b,[["render",k]]);export{J as __pageData,D as default};
